// This file should ideally fetch from real JSON reports generated by Pytest, Pytest-Cov, Behave, and Mutmut.
// For demonstration, we load static data from sample_data.json or mock it.

document.addEventListener("DOMContentLoaded", () => {
    fetchData();

    document.getElementById("refresh-btn").addEventListener("click", () => {
        fetchData();
    });
});

async function fetchData() {
    try {
        // In a real scenario, fetch actual reports (e.g. pytest-report.json)
        const response = await fetch("sample_data.json");
        if (!response.ok) throw new Error("Failed to load data");
        const data = await response.json();
        
        updateDashboard(data);
    } catch (error) {
        console.error("Error fetching QA data:", error);
        // Fallback to mock data if sample_data.json is not served properly (e.g. CORS/file protocol)
        loadMockData();
    }
}

function updateDashboard(data) {
    // Update timestamp
    document.getElementById("last-updated").innerText = new Date().toLocaleString();

    // Unit Tests
    document.getElementById("unit-total").innerText = data.unit.total;
    document.getElementById("unit-passed").innerText = data.unit.passed;
    document.getElementById("unit-failed").innerText = data.unit.failed;

    // Coverage
    const covPercent = data.coverage.percentage;
    document.getElementById("coverage-percent").innerText = covPercent;
    document.getElementById("coverage-bar").style.width = `${covPercent}%`;
    if (covPercent < 80) document.getElementById("coverage-bar").classList.replace("bg-emerald-400", "bg-amber-400");
    if (covPercent < 50) document.getElementById("coverage-bar").classList.replace("bg-amber-400", "bg-red-500");

    // BDD
    document.getElementById("bdd-total").innerText = data.bdd.total;
    document.getElementById("bdd-passed").innerText = data.bdd.passed;
    document.getElementById("bdd-failed").innerText = data.bdd.failed;

    // Mutation
    document.getElementById("mut-total").innerText = data.mutation.total;
    document.getElementById("mut-survived").innerText = data.mutation.survived;
    document.getElementById("mut-killed").innerText = data.mutation.killed;

    // Populate Tables
    populateUnitTests(data.unit.recent_tests);
    populateBddTests(data.bdd.features);
}

function populateUnitTests(tests) {
    const tbody = document.getElementById("unit-tests-body");
    tbody.innerHTML = "";
    
    tests.forEach(test => {
        const tr = document.createElement("tr");
        tr.className = "hover:bg-gray-700 transition";
        const statusIcon = test.status === "passed" 
            ? '<span class="text-green-400 bg-green-400/10 px-2 py-1 rounded text-xs">Passed</span>'
            : '<span class="text-red-400 bg-red-400/10 px-2 py-1 rounded text-xs">Failed</span>';
            
        tr.innerHTML = `
            <td class="py-3 px-3 font-mono text-gray-300">${test.name}</td>
            <td class="py-3 px-3 text-gray-400">${test.duration}s</td>
            <td class="py-3 px-3">${statusIcon}</td>
        `;
        tbody.appendChild(tr);
    });
}

function populateBddTests(features) {
    const tbody = document.getElementById("bdd-tests-body");
    tbody.innerHTML = "";
    
    features.forEach(feature => {
        const tr = document.createElement("tr");
        tr.className = "hover:bg-gray-700 transition";
        const statusIcon = feature.status === "passed" 
            ? '<span class="text-green-400"><i class="fa-solid fa-check"></i></span>'
            : '<span class="text-red-400"><i class="fa-solid fa-xmark"></i></span>';
            
        tr.innerHTML = `
            <td class="py-3 px-3">
                <div class="font-semibold text-gray-200">${feature.name}</div>
                <div class="text-xs text-gray-500">${feature.scenario}</div>
            </td>
            <td class="py-3 px-3 text-gray-400 text-xs">${feature.steps} steps executed</td>
            <td class="py-3 px-3">${statusIcon}</td>
        `;
        tbody.appendChild(tr);
    });
}

// Fallback if fetch fails (e.g., when opening index.html directly from file://)
